import java.util.Arrays;
import java.util.List;

public int[][] buildMatrix(int k, List<List<Integer>> rowConditions, List<List<Integer>> colConditions) {
    int[] row = new int[k + 1], col = new int[k + 1];
    for (List<Integer> condition : rowConditions) {
        if (row[condition.get(0)] >= row[condition.get(1)]) return new int[][]{};
        row[condition.get(1)] = row[condition.get(0)] + 1;
    }
    for (List<Integer> condition : colConditions) {
        if (col[condition.get(0)] >= col[condition.get(1)]) return new int[][]{};
        col[condition.get(1)] = col[condition.get(0)] + 1;
    }
    int[][] matrix = new int[k][k];
    for (int i = 1; i <= k; ++i) {
        matrix[row[i]][col[i]] = i;
    }
    return matrix;
}
